{"content": "     1|{
     2|  "$schema": "http://json-schema.org/draft-07/schema#",
     3|  "title": "Architecture Registry",
     4|  "description": "Machine-readable registry of governed components. Each entry maps a role key to its governance metadata. Governed by the structural ADR that establishes the registry.",
     5|  "type": "object",
     6|  "properties": {
     7|    "$schema": {
     8|      "type": "string",
     9|      "description": "Reference to this schema file"
    10|    },
    11|    "metadata": {
    12|      "type": "object",
    13|      "description": "Registry-level metadata",
    14|      "properties": {
    15|        "governed_by": {
    16|          "type": "string",
    17|          "description": "ADR that governs this registry's structure and semantics"
    18|        },
    19|        "last_updated": {
    20|          "type": "string",
    21|          "format": "date",
    22|          "description": "Date of last registry update"
    23|        }
    24|      },
    25|      "required": ["governed_by", "last_updated"]
    26|    },
    27|    "components": {
    28|      "type": "object",
    29|      "description": "Component entries keyed by role name",
    30|      "additionalProperties": {
    31|        "$ref": "#/definitions/component"
    32|      }
    33|    }
    34|  },
    35|  "required": ["metadata", "components"],
    36|  "definitions": {
    37|    "component": {
    38|      "type": "object",
    39|      "description": "A single component in the registry",
    40|      "properties": {
    41|        "description": {
    42|          "type": "string",
    43|          "description": "Brief description of the component's role"
    44|        },
    45|        "governance_status": {
    46|          "type": "string",
    47|          "enum": ["governed", "pre_governance", "pending"],
    48|          "description": "governed = has ADR and (if applicable) spec; pre_governance = predates framework; pending = governance artefacts in progress"
    49|        },
    50|        "governing_adr": {
    51|          "type": ["string", "null"],
    52|          "description": "ADR number that governs this component (null if pre_governance)"
    53|        },
    54|        "spec": {
    55|          "type": ["string", "null"],
    56|          "description": "Path to the Gov spec for this component (null if no spec required)"
    57|        },
    58|        "category": {
    59|          "type": "string",
    60|          "description": "Component category (project-defined, e.g. 'platform', 'service', 'network')"
    61|        },
    62|        "sites": {
    63|          "type": "array",
    64|          "items": {
    65|            "type": "string"
    66|          },
    67|          "description": "Sites where this component is deployed (project-defined site identifiers)"
    68|        }
    69|      },
    70|      "required": ["description", "governance_status"],
    71|      "additionalProperties": false
    72|    }
    73|  }
    74|}
    75|", "total_lines": 74, "file_size": 2518, "truncated": false, "is_binary": false, "is_image": false}
